static void rpki_rtr_pdu_print (netdissect_options *ndo, const u_char *tptr, u_int indent)
{
    const rpki_rtr_pdu *pdu_header;
    u_int pdu_type, pdu_len, hexdump;
    const u_char *msg;

    pdu_header = (rpki_rtr_pdu *)tptr;
    pdu_type = pdu_header->pdu_type;
    pdu_len = EXTRACT_32BITS(pdu_header->length);
    hexdump = FALSE;

    ND_PRINT((ndo, "%sRPKI-RTRv%u, %s PDU (%u), length: %u",
       indent_string(8),
       pdu_header->version,
       tok2str(rpki_rtr_pdu_values, "Unknown", pdu_type),
       pdu_type, pdu_len));

    switch (pdu_type) {

    case RPKI_RTR_SERIAL_NOTIFY_PDU:
    case RPKI_RTR_SERIAL_QUERY_PDU:
    case RPKI_RTR_END_OF_DATA_PDU:
        msg = (const u_char *)(pdu_header + 1);
    ND_PRINT((ndo, "%sSession ID: 0x%04x, Serial: %u",
           indent_string(indent+2),
           EXTRACT_16BITS(pdu_header->u.session_id),
           EXTRACT_32BITS(msg)));
    break;

    case RPKI_RTR_RESET_QUERY_PDU:
    case RPKI_RTR_CACHE_RESET_PDU:
        break;

    case RPKI_RTR_CACHE_RESPONSE_PDU:
    ND_PRINT((ndo, "%sSession ID: 0x%04x",
           indent_string(indent+2),
           EXTRACT_16BITS(pdu_header->u.session_id)));
    break;

    case RPKI_RTR_IPV4_PREFIX_PDU:
    {
        rpki_rtr_pdu_ipv4_prefix *pdu;
        pdu = (rpki_rtr_pdu_ipv4_prefix *)tptr;
        ND_PRINT((ndo, "%sIPv4 Prefix %s/%u-%u, origin-as %u, flags 0x%02x",
           indent_string(indent+2),
           ipaddr_string(ndo, pdu->prefix),
           pdu->prefix_length, pdu->max_length,
           EXTRACT_32BITS(pdu->as), pdu->flags));
    }
    break;

#ifdef INET6
    case RPKI_RTR_IPV6_PREFIX_PDU:
    {
        rpki_rtr_pdu_ipv6_prefix *pdu;
        pdu = (rpki_rtr_pdu_ipv6_prefix *)tptr;
        ND_PRINT((ndo, "%sIPv6 Prefix %s/%u-%u, origin-as %u, flags 0x%02x",
           indent_string(indent+2),
           ip6addr_string(ndo, pdu->prefix),
           pdu->prefix_length, pdu->max_length,
           EXTRACT_32BITS(pdu->as), pdu->flags));
    }
    break;
#endif

    case RPKI_RTR_ERROR_REPORT_PDU:
    {
        rpki_rtr_pdu_error_report *pdu;
        u_int encapsulated_pdu_length, text_length, tlen, error_code;
        u_char buf[80];

        pdu = (rpki_rtr_pdu_error_report *)tptr;
        encapsulated_pdu_length = EXTRACT_32BITS(pdu->encapsulated_pdu_length);
        tlen = pdu_len;

        error_code = EXTRACT_16BITS(pdu->pdu_header.u.error_code);
        ND_PRINT((ndo, "%sError code: %s (%u), Encapsulated PDU length: %u",
           indent_string(indent+2),
           tok2str(rpki_rtr_error_codes, "Unknown", error_code),
           error_code, encapsulated_pdu_length));

        tptr += sizeof(*pdu);
        tlen -= sizeof(*pdu);

        if (encapsulated_pdu_length && (encapsulated_pdu_length <= tlen)) {
            ND_PRINT((ndo, "%s-----encapsulated PDU-----", indent_string(indent+4)));
            rpki_rtr_pdu_print(ndo, tptr, indent+2);
        }

        tptr += encapsulated_pdu_length;
        tlen -= encapsulated_pdu_length;

        text_length = 0;
        if (tlen > 4) {
            text_length = EXTRACT_32BITS(tptr);
            tptr += 4;
            tlen -= 4;
        }
        if (text_length && (text_length <= tlen)) {
            memcpy(buf, tptr, min(sizeof(buf)-1, text_length));
            buf[text_length] = '\0';
            ND_PRINT((ndo, "%sError text: %s", indent_string(indent+2), buf));
        }
    }
    break;

    default:
        hexdump = TRUE;
    }

    if (ndo->ndo_vflag > 1 || (ndo->ndo_vflag && hexdump)) {
        print_unknown_data(ndo,tptr,"\n\t  ", pdu_len);
    }
}

void
geonet_print(netdissect_options *ndo, const u_char *eth, const u_char *bp, u_int length)
{
	ND_PRINT((ndo, "GeoNet src:%s; ", etheraddr_string(ndo, eth+6)));

	if (length >= 36) {
		/* Process Common Header */
		int version = bp[0] >> 4;
		int next_hdr = bp[0] & 0x0f;
		int hdr_type = bp[1] >> 4;
		int hdr_subtype = bp[1] & 0x0f;
		uint16_t payload_length = EXTRACT_16BITS(bp+4);
		int hop_limit = bp[7];
		const char *next_hdr_txt = "Unknown";
		const char *hdr_type_txt = "Unknown";
		int hdr_size = -1;

		switch (next_hdr) {
			case 0: next_hdr_txt = "Any"; break;
			case 1: next_hdr_txt = "BTP-A"; break;
			case 2: next_hdr_txt = "BTP-B"; break;
			case 3: next_hdr_txt = "IPv6"; break;
		}

		switch (hdr_type) {
			case 0: hdr_type_txt = "Any"; break;
			case 1: hdr_type_txt = "Beacon"; break;
			case 2: hdr_type_txt = "GeoUnicast"; break;
			case 3: switch (hdr_subtype) {
					case 0: hdr_type_txt = "GeoAnycastCircle"; break;
					case 1: hdr_type_txt = "GeoAnycastRect"; break;
					case 2: hdr_type_txt = "GeoAnycastElipse"; break;
				}
				break;
			case 4: switch (hdr_subtype) {
					case 0: hdr_type_txt = "GeoBroadcastCircle"; break;
					case 1: hdr_type_txt = "GeoBroadcastRect"; break;
					case 2: hdr_type_txt = "GeoBroadcastElipse"; break;
				}
				break;
			case 5: switch (hdr_subtype) {
					case 0: hdr_type_txt = "TopoScopeBcast-SH"; break;
					case 1: hdr_type_txt = "TopoScopeBcast-MH"; break;
				}
				break;
			case 6: switch (hdr_subtype) {
					case 0: hdr_type_txt = "LocService-Request"; break;
					case 1: hdr_type_txt = "LocService-Reply"; break;
				}
				break;
		}

		ND_PRINT((ndo, "v:%d ", version));
		ND_PRINT((ndo, "NH:%d-%s ", next_hdr, next_hdr_txt));
		ND_PRINT((ndo, "HT:%d-%d-%s ", hdr_type, hdr_subtype, hdr_type_txt));
		ND_PRINT((ndo, "HopLim:%d ", hop_limit));
		ND_PRINT((ndo, "Payload:%d ", payload_length));
		print_long_pos_vector(ndo, bp + 8);

		/* Skip Common Header */
		length -= 36;
		bp += 36;

		/* Process Extended Headers */
		switch (hdr_type) {
			case 0: /* Any */
				hdr_size = 0;
				break;
			case 1: /* Beacon */
				hdr_size = 0;
				break;
			case 2: /* GeoUnicast */
				break;
			case 3: switch (hdr_subtype) {
						case 0: /* GeoAnycastCircle */
							break;
						case 1: /* GeoAnycastRect */
							break;
						case 2: /* GeoAnycastElipse */
							break;
					}
					break;
			case 4: switch (hdr_subtype) {
						case 0: /* GeoBroadcastCircle */
							break;
						case 1: /* GeoBroadcastRect */
							break;
						case 2: /* GeoBroadcastElipse */
							break;
					}
					break;
			case 5: switch (hdr_subtype) {
						case 0: /* TopoScopeBcast-SH */
							hdr_size = 0;
							break;
						case 1: /* TopoScopeBcast-MH */
							hdr_size = 68 - 36;
							break;
					}
					break;
			case 6: switch (hdr_subtype) {
						case 0: /* LocService-Request */
							break;
						case 1: /* LocService-Reply */
							break;
					}
					break;
		}

		/* Skip Extended headers */
		if (hdr_size >= 0) {
			length -= hdr_size;
			bp += hdr_size;
			switch (next_hdr) {
				case 0: /* Any */
					break;
				case 1:
				case 2: /* BTP A/B */
					print_btp(ndo, bp);
					length -= 4;
					bp += 4;
					print_btp_body(ndo, bp, length);
					break;
				case 3: /* IPv6 */
					break;
			}
		}
	} else {
		ND_PRINT((ndo, "Malformed (small) "));
	}

	/* Print user data part */
	if (ndo->ndo_vflag)
		ND_DEFAULTPRINT(bp, length);
}

static u_char * isakmp_sub_print(u_char np, struct isakmp_gen *ext, u_char *ep, u_int32_t phase, u_int32_t doi, u_int32_t proto) {
	u_char *cp;
	static int depth = 0;
	int i;
	struct isakmp_gen e;

	cp = (u_char *)ext;

	while (np) {
		safememcpy(&e, ext, sizeof(e));

		if (ep < (u_char *)ext + ntohs(e.len)) {
			printf(" [|%s]", NPSTR(np));
			cp = ep + 1;
			break;
		}
		depth++;
		printf("\n");
		for (i = 0; i < depth; i++)
			printf("    ");
		printf("(");
		cp = isakmp_sub0_print(np, ext, ep, phase, doi, proto);
		printf(")");
		depth--;

		np = e.np;
		ext = (struct isakmp_gen *)cp;
	}
	return cp;
}

static void bgp_update_print(const u_char *dat, int length) {
	struct bgp bgp;
	struct bgp_attr bgpa;
	const u_char *p;
	int len;
	int i;
	char tokbuf[TOKBUFSIZE];

	TCHECK2(dat[0], BGP_SIZE);
	memcpy(&bgp, dat, BGP_SIZE);
	p = dat + BGP_SIZE;	/*XXX*/

	/* Unfeasible routes */
	len = EXTRACT_16BITS(p);
	if (len) {
		/*
		 * Without keeping state from the original NLRI message,
		 * it's not possible to tell if this a v4 or v6 route,
		 * so only try to decode it if we're not v6 enabled.
	         */
#ifdef INET6
		printf("\n\t  Withdrawn routes: %d bytes", len);
#else
		char buf[MAXHOSTNAMELEN + 100];
		int wpfx;

		TCHECK2(p[2], len);
		i = 2;

		printf("\n\t  Withdrawn routes:");

		while(i < 2 + len) {
			wpfx = decode_prefix4(&p[i], buf, sizeof(buf));
			if (wpfx == -1) {
				printf("\n\t    (illegal prefix length)");
				break;
			} else if (wpfx == -2)
				goto trunc;
			else {
				i += wpfx;
				printf("\n\t    %s", buf);
			}
		}
#endif
	}
	p += 2 + len;

	TCHECK2(p[0], 2);
	len = EXTRACT_16BITS(p);

        if (len == 0 && length == BGP_UPDATE_MINSIZE) {
            printf("\n\t  End-of-Rib Marker (empty NLRI)");
            return;
        }

	if (len) {
		/* do something more useful!*/
		i = 2;
		while (i < 2 + len) {
			int alen, aoff;

			TCHECK2(p[i], sizeof(bgpa));
			memcpy(&bgpa, &p[i], sizeof(bgpa));
			alen = bgp_attr_len(&bgpa);
			aoff = bgp_attr_off(&bgpa);

		       printf("\n\t  %s (%u), length: %u",
                              tok2strbuf(bgp_attr_values, "Unknown Attribute",
					 bgpa.bgpa_type,
					 tokbuf, sizeof(tokbuf)),
                              bgpa.bgpa_type,
                              alen);

			if (bgpa.bgpa_flags) {
				printf(", Flags [%s%s%s%s",
					bgpa.bgpa_flags & 0x80 ? "O" : "",
					bgpa.bgpa_flags & 0x40 ? "T" : "",
					bgpa.bgpa_flags & 0x20 ? "P" : "",
					bgpa.bgpa_flags & 0x10 ? "E" : "");
				if (bgpa.bgpa_flags & 0xf)
					printf("+%x", bgpa.bgpa_flags & 0xf);
				printf("]: ");
			}
			if (!bgp_attr_print(&bgpa, &p[i + aoff], alen))
				goto trunc;
			i += aoff + alen;
		}
	} 
	p += 2 + len;

	if (dat + length > p) {
		printf("\n\t  Updated routes:");
		while (dat + length > p) {
			char buf[MAXHOSTNAMELEN + 100];
			i = decode_prefix4(p, buf, sizeof(buf));
			if (i == -1) {
				printf("\n\t    (illegal prefix length)");
				break;
			} else if (i == -2)
				goto trunc;
			else {
				printf("\n\t    %s", buf);
				p += i;
			}
		}
	}
	return;
trunc:
	printf("[|BGP]");
}

#define MFR_ID_STRING_MAXLEN 50

struct ie_tlv_header_t {
    uint8_t ie_type;
    uint8_t ie_len;
};
u_int 
mfr_print(netdissect_options *ndo,
          register const u_char *p, u_int length)
{
    u_int tlen,idx,hdr_len = 0;
    uint16_t sequence_num;
    uint8_t ie_type,ie_len;
    const uint8_t *tptr;

/*
 * FRF.16 Link Integrity Control Frame
 *
 *      7    6    5    4    3    2    1    0
 *    +----+----+----+----+----+----+----+----+
 *    | B  | E  | C=1| 0    0    0    0  | EA |
 *    +----+----+----+----+----+----+----+----+
 *    | 0    0    0    0    0    0    0    0  |
 *    +----+----+----+----+----+----+----+----+
 *    |              message type             |
 *    +----+----+----+----+----+----+----+----+
 */

    ND_TCHECK2(*p, 4); /* minimum frame header length */

    if ((p[0] & MFR_BEC_MASK) == MFR_CTRL_FRAME && p[1] == 0) {
        ND_PRINT((ndo, "FRF.16 Control, Flags [%s], %s, length %u",
               bittok2str(frf_flag_values,"none",(p[0] & MFR_BEC_MASK)),
               tok2str(mfr_ctrl_msg_values,"Unknown Message (0x%02x)",p[2]),
               length));
        tptr = p + 3;
        tlen = length -3;
        hdr_len = 3;

        if (!ndo->ndo_vflag)
            return hdr_len;

        while (tlen>sizeof(struct ie_tlv_header_t)) {
            ND_TCHECK2(*tptr, sizeof(struct ie_tlv_header_t));
            ie_type=tptr[0];
            ie_len=tptr[1];

            ND_PRINT((ndo, "\n\tIE %s (%u), length %u: ",
                   tok2str(mfr_ctrl_ie_values,"Unknown",ie_type),
                   ie_type,
                   ie_len));

            /* infinite loop check */
            if (ie_type == 0 || ie_len <= sizeof(struct ie_tlv_header_t))
                return hdr_len;

            ND_TCHECK2(*tptr, ie_len);
            tptr+=sizeof(struct ie_tlv_header_t);
            /* tlv len includes header */
            ie_len-=sizeof(struct ie_tlv_header_t);
            tlen-=sizeof(struct ie_tlv_header_t);

            switch (ie_type) {

            case MFR_CTRL_IE_MAGIC_NUM:
                ND_PRINT((ndo, "0x%08x", EXTRACT_32BITS(tptr)));
                break;

            case MFR_CTRL_IE_BUNDLE_ID: /* same message format */
            case MFR_CTRL_IE_LINK_ID:
                for (idx = 0; idx < ie_len && idx < MFR_ID_STRING_MAXLEN; idx++) {
                    if (*(tptr+idx) != 0) /* don't print null termination */
                        safeputchar(ndo, *(tptr + idx));
                    else
                        break;
                }
                break;

            case MFR_CTRL_IE_TIMESTAMP:
                if (ie_len == sizeof(struct timeval)) {
                    ts_print(ndo, (const struct timeval *)tptr);
                    break;
                }
                /* fall through and hexdump if no unix timestamp */

                /*
                 * FIXME those are the defined IEs that lack a decoder
                 * you are welcome to contribute code ;-)
                 */

            case MFR_CTRL_IE_VENDOR_EXT:
            case MFR_CTRL_IE_CAUSE:

            default:
                if (ndo->ndo_vflag <= 1)
                    print_unknown_data(ndo, tptr, "\n\t  ", ie_len);
                break;
            }

            /* do we want to see a hexdump of the IE ? */
            if (ndo->ndo_vflag > 1 )
                print_unknown_data(ndo, tptr, "\n\t  ", ie_len);

            tlen-=ie_len;
            tptr+=ie_len;
        }
        return hdr_len;
    }
/*
 * FRF.16 Fragmentation Frame
 *
 *      7    6    5    4    3    2    1    0
 *    +----+----+----+----+----+----+----+----+
 *    | B  | E  | C=0|seq. (high 4 bits) | EA  |
 *    +----+----+----+----+----+----+----+----+
 *    |        sequence  (low 8 bits)         |
 *    +----+----+----+----+----+----+----+----+
 *    |        DLCI (6 bits)        | CR | EA  |
 *    +----+----+----+----+----+----+----+----+
 *    |   DLCI (4 bits)   |FECN|BECN| DE | EA |
 *    +----+----+----+----+----+----+----+----+
 */

    sequence_num = (p[0]&0x1e)<<7 | p[1];
    /* whole packet or first fragment ? */
    if ((p[0] & MFR_BEC_MASK) == MFR_FRAG_FRAME ||
        (p[0] & MFR_BEC_MASK) == MFR_B_BIT) {
        ND_PRINT((ndo, "FRF.16 Frag, seq %u, Flags [%s], ",
               sequence_num,
               bittok2str(frf_flag_values,"none",(p[0] & MFR_BEC_MASK))));
        hdr_len = 2;
        fr_print(ndo, p+hdr_len,length-hdr_len);
        return hdr_len;
    }

    /* must be a middle or the last fragment */
    ND_PRINT((ndo, "FRF.16 Frag, seq %u, Flags [%s]",
           sequence_num,
           bittok2str(frf_flag_values,"none",(p[0] & MFR_BEC_MASK))));
    print_unknown_data(ndo, p, "\n\t", length);

    return hdr_len;

 trunc:
    ND_PRINT((ndo, "[|mfr]"));
    return length;
}

/* an NLPID of 0xb1 indicates a 2-byte
 * FRF.15 header
 *
 *      7    6    5    4    3    2    1    0
 *    +----+----+----+----+----+----+----+----+
 *    ~              Q.922 header             ~
 *    +----+----+----+----+----+----+----+----+
 *    |             NLPID (8 bits)            | NLPID=0xb1
 *    +----+----+----+----+----+----+----+----+
 *    | B  | E  | C  |seq. (high 4 bits) | R  |
 *    +----+----+----+----+----+----+----+----+
 *    |        sequence  (low 8 bits)         |
 *    +----+----+----+----+----+----+----+----+
 */

static int
lmp_print_data_link_subobjs(netdissect_options *ndo, const u_char *obj_tptr,
                            int total_subobj_len, int offset)
{
    int hexdump = FALSE;
    int subobj_type, subobj_len;

    union { /* int to float conversion buffer */
        float f;
        uint32_t i;
    } bw;

    while (total_subobj_len > 0 && hexdump == FALSE ) {
	subobj_type = EXTRACT_8BITS(obj_tptr+offset);
	subobj_len  = EXTRACT_8BITS(obj_tptr+offset+1);
	ND_PRINT((ndo, "\n\t    Subobject, Type: %s (%u), Length: %u",
		tok2str(lmp_data_link_subobj,
			"Unknown",
			subobj_type),
			subobj_type,
			subobj_len));
	if (subobj_len < 4) {
	    ND_PRINT((ndo, " (too short)"));
	    break;
	}
	if ((subobj_len % 4) != 0) {
	    ND_PRINT((ndo, " (not a multiple of 4)"));
	    break;
	}
	if (total_subobj_len < subobj_len) {
	    ND_PRINT((ndo, " (goes past the end of the object)"));
	    break;
	}
	switch(subobj_type) {
	case INT_SWITCHING_TYPE_SUBOBJ:
	    ND_PRINT((ndo, "\n\t      Switching Type: %s (%u)",
		tok2str(gmpls_switch_cap_values,
			"Unknown",
			EXTRACT_8BITS(obj_tptr+offset+2)),
		EXTRACT_8BITS(obj_tptr+offset+2)));
	    ND_PRINT((ndo, "\n\t      Encoding Type: %s (%u)",
		tok2str(gmpls_encoding_values,
			"Unknown",
			EXTRACT_8BITS(obj_tptr+offset+3)),
		EXTRACT_8BITS(obj_tptr+offset+3)));
	    bw.i = EXTRACT_32BITS(obj_tptr+offset+4);
	    ND_PRINT((ndo, "\n\t      Min Reservable Bandwidth: %.3f Mbps",
                bw.f*8/1000000));
	    bw.i = EXTRACT_32BITS(obj_tptr+offset+8);
	    ND_PRINT((ndo, "\n\t      Max Reservable Bandwidth: %.3f Mbps",
                bw.f*8/1000000));
	    break;
	case WAVELENGTH_SUBOBJ:
	    ND_PRINT((ndo, "\n\t      Wavelength: %u",
		EXTRACT_32BITS(obj_tptr+offset+4)));
	    break;
	default:
	    /* Any Unknown Subobject ==> Exit loop */
	    hexdump=TRUE;
	    break;
	}
	total_subobj_len-=subobj_len;
	offset+=subobj_len;
    }
    return (hexdump);
}

static int
rx_cache_find(const struct rx_header *rxh, const struct ip *ip, int sport,
	      int32_t *opcode)
{
	int i;
	struct rx_cache_entry *rxent;
	uint32_t clip;
	uint32_t sip;

	UNALIGNED_MEMCPY(&clip, &ip->ip_dst, sizeof(uint32_t));
	UNALIGNED_MEMCPY(&sip, &ip->ip_src, sizeof(uint32_t));

	/* Start the search where we last left off */

	i = rx_cache_hint;
	do {
		rxent = &rx_cache[i];
		if (rxent->callnum == EXTRACT_32BITS(&rxh->callNumber) &&
		    rxent->client.s_addr == clip &&
		    rxent->server.s_addr == sip &&
		    rxent->serviceId == EXTRACT_32BITS(&rxh->serviceId) &&
		    rxent->dport == sport) {

			/* We got a match! */

			rx_cache_hint = i;
			*opcode = rxent->opcode;
			return(1);
		}
		if (++i >= RX_CACHE_SIZE)
			i = 0;
	} while (i != rx_cache_hint);

	/* Our search failed */
	return(0);
}

static void
rpl_daoack_print(netdissect_options *ndo,
                 const u_char *bp, u_int length)
{
        const struct nd_rpl_daoack *daoack = (const struct nd_rpl_daoack *)bp;
        const char *dagid_str = "<elided>";

        ND_TCHECK2(*daoack, ND_RPL_DAOACK_MIN_LEN);
        if (length < ND_RPL_DAOACK_MIN_LEN)
        	goto tooshort;

        bp += ND_RPL_DAOACK_MIN_LEN;
        length -= ND_RPL_DAOACK_MIN_LEN;
        if(RPL_DAOACK_D(daoack->rpl_flags)) {
                ND_TCHECK2(daoack->rpl_dagid, DAGID_LEN);
                if (length < DAGID_LEN)
                	goto tooshort;
                dagid_str = ip6addr_string (ndo, daoack->rpl_dagid);
                bp += DAGID_LEN;
                length -= DAGID_LEN;
        }

        ND_PRINT((ndo, " [dagid:%s,seq:%u,instance:%u,status:%u]",
                  dagid_str,
                  daoack->rpl_daoseq,
                  daoack->rpl_instanceid,
                  daoack->rpl_status));

        /* no officially defined options for DAOACK, but print any we find */
        if(ndo->ndo_vflag > 1) {
                const struct rpl_dio_genoption *opt = (const struct rpl_dio_genoption *)bp;
                rpl_dio_printopt(ndo, opt, length);
        }
	return;

trunc:
	ND_PRINT((ndo," [|dao-truncated]"));
	return;

tooshort:
	ND_PRINT((ndo," [|dao-length too short]"));
	return;
}

static void
print_attr_string(netdissect_options *ndo,
                  register const u_char *data, u_int length, u_short attr_code)
{
   register u_int i;

   ND_TCHECK2(data[0],length);

   switch(attr_code)
   {
      case TUNNEL_PASS:
           if (length < 3)
              goto trunc;
           if (*data && (*data <=0x1F) )
              ND_PRINT((ndo, "Tag[%u] ", *data));
           else
              ND_PRINT((ndo, "Tag[Unused] "));
           data++;
           length--;
           ND_PRINT((ndo, "Salt %u ", EXTRACT_16BITS(data)));
           data+=2;
           length-=2;
        break;
      case TUNNEL_CLIENT_END:
      case TUNNEL_SERVER_END:
      case TUNNEL_PRIV_GROUP:
      case TUNNEL_ASSIGN_ID:
      case TUNNEL_CLIENT_AUTH:
      case TUNNEL_SERVER_AUTH:
           if (*data <= 0x1F)
           {
              if (length < 1)
                 goto trunc;
              if (*data)
                ND_PRINT((ndo, "Tag[%u] ", *data));
              else
                ND_PRINT((ndo, "Tag[Unused] "));
              data++;
              length--;
           }
        break;
      case EGRESS_VLAN_NAME:
           if (length < 1)
              goto trunc;
           ND_PRINT((ndo, "%s (0x%02x) ",
                  tok2str(rfc4675_tagged,"Unknown tag",*data),
                  *data));
           data++;
           length--;
        break;
   }

   for (i=0; i < length && *data; i++, data++)
       ND_PRINT((ndo, "%c", (*data < 32 || *data > 126) ? '.' : *data));

   return;

   trunc:
      ND_PRINT((ndo, "%s", tstr));
}

static const u_char *
ikev1_n_print(netdissect_options *ndo, u_char tpay _U_,
      const struct isakmp_gen *ext, u_int item_len,
      const u_char *ep, uint32_t phase _U_, uint32_t doi0 _U_,
      uint32_t proto0 _U_, int depth _U_)
{
    const struct ikev1_pl_n *p;
    struct ikev1_pl_n n;
    const u_char *cp;
    const u_char *ep2;
    uint32_t doi;
    uint32_t proto;
    static const char *notify_error_str[] = {
        NULL, "INVALID-PAYLOAD-TYPE", "DOI-NOT-SUPPORTED", "SITUATION-NOT-SUPPORTED", "INVALID-COOKIE", "INVALID-MAJOR-VERSION", "INVALID-MINOR-VERSION", "INVALID-EXCHANGE-TYPE", "INVALID-FLAGS", "INVALID-MESSAGE-ID", "INVALID-PROTOCOL-ID", "INVALID-SPI", "INVALID-TRANSFORM-ID", "ATTRIBUTES-NOT-SUPPORTED", "NO-PROPOSAL-CHOSEN", "BAD-PROPOSAL-SYNTAX", "PAYLOAD-MALFORMED", "INVALID-KEY-INFORMATION", "INVALID-ID-INFORMATION", "INVALID-CERT-ENCODING", "INVALID-CERTIFICATE", "CERT-TYPE-UNSUPPORTED", "INVALID-CERT-AUTHORITY", "INVALID-HASH-INFORMATION", "AUTHENTICATION-FAILED", "INVALID-SIGNATURE", "ADDRESS-NOTIFICATION", "NOTIFY-SA-LIFETIME", "CERTIFICATE-UNAVAILABLE", "UNSUPPORTED-EXCHANGE-TYPE", "UNEQUAL-PAYLOAD-LENGTHS"
    };
    static const char *ipsec_notify_error_str[] = {"RESERVED"};
    static const char *notify_status_str[] = {"CONNECTED"};
    static const char *ipsec_notify_status_str[] = {"RESPONDER-LIFETIME", "REPLAY-STATUS", "INITIAL-CONTACT"};

#define NOTIFY_ERROR_STR(x) STR_OR_ID((x), notify_error_str)
#define IPSEC_NOTIFY_ERROR_STR(x) STR_OR_ID((u_int)((x) - 8192), ipsec_notify_error_str)
#define NOTIFY_STATUS_STR(x) STR_OR_ID((u_int)((x) - 16384), notify_status_str)
#define IPSEC_NOTIFY_STATUS_STR(x) STR_OR_ID((u_int)((x) - 24576), ipsec_notify_status_str)

    ND_PRINT((ndo,"%s:", NPSTR(ISAKMP_NPTYPE_N)));

    p = (const struct ikev1_pl_n *)ext;
    ND_TCHECK(*p);
    UNALIGNED_MEMCPY(&n, ext, sizeof(n));
    doi = ntohl(n.doi);
    proto = n.prot_id;
    if (doi != 1) {
        ND_PRINT((ndo," doi=%d", doi));
        ND_PRINT((ndo," proto=%d", proto));
        if (ntohs(n.type) < 8192)
            ND_PRINT((ndo," type=%s", NOTIFY_ERROR_STR(ntohs(n.type))));
        else if (ntohs(n.type) < 16384)
            ND_PRINT((ndo," type=%s", numstr(ntohs(n.type))));
        else if (ntohs(n.type) < 24576)
            ND_PRINT((ndo," type=%s", NOTIFY_STATUS_STR(ntohs(n.type))));
        else
            ND_PRINT((ndo," type=%s", numstr(ntohs(n.type))));
        if (n.spi_size) {
            ND_PRINT((ndo," spi="));
            if (!rawprint(ndo, (const uint8_t *)(p + 1), n.spi_size))
                goto trunc;
        }
        return (const u_char *)(p + 1) + n.spi_size;
    }

    ND_PRINT((ndo," doi=ipsec"));
    ND_PRINT((ndo," proto=%s", PROTOIDSTR(proto)));
    if (ntohs(n.type) < 8192)
        ND_PRINT((ndo," type=%s", NOTIFY_ERROR_STR(ntohs(n.type))));
    else if (ntohs(n.type) < 16384)
        ND_PRINT((ndo," type=%s", IPSEC_NOTIFY_ERROR_STR(ntohs(n.type))));
    else if (ntohs(n.type) < 24576)
        ND_PRINT((ndo," type=%s", NOTIFY_STATUS_STR(ntohs(n.type))));
    else if (ntohs(n.type) < 32768)
        ND_PRINT((ndo," type=%s", IPSEC_NOTIFY_STATUS_STR(ntohs(n.type))));
    else
        ND_PRINT((ndo," type=%s", numstr(ntohs(n.type))));
    if (n.spi_size) {
        ND_PRINT((ndo," spi="));
        if (!rawprint(ndo, (const uint8_t *)(p + 1), n.spi_size))
            goto trunc;
    }

    cp = (const u_char *)(p + 1) + n.spi_size;
    ep2 = (const u_char *)p + item_len;

    if (cp < ep) {
        switch (ntohs(n.type)) {
        case IPSECDOI_NTYPE_RESPONDER_LIFETIME:
            {
                const struct attrmap *map = oakley_t_map;
                size_t nmap = sizeof(oakley_t_map)/sizeof(oakley_t_map[0]);
                ND_PRINT((ndo," attrs=("));
                while (cp < ep && cp < ep2) {
                    cp = ikev1_attrmap_print(ndo, cp, ep2, map, nmap);
                    if (cp == NULL) {
                        ND_PRINT((ndo,")"));
                        goto trunc;
                    }
                }
                ND_PRINT((ndo,")"));
                break;
            }
        case IPSECDOI_NTYPE_REPLAY_STATUS:
            ND_PRINT((ndo," status=("));
            ND_PRINT((ndo,"replay detection %sabled", EXTRACT_32BITS(cp) ? "en" : "dis"));
            ND_PRINT((ndo,")"));
            break;
        default:
            if (ndo->ndo_vflag > 3) {
                ND_PRINT((ndo," data=("));
                if (!rawprint(ndo, (const uint8_t *)(cp), ep - cp))
                    goto trunc;
                ND_PRINT((ndo,")"));
            } else {
                if (!ike_show_somedata(ndo, cp, ep))
                    goto trunc;
            }
            break;
        }
    }
    return (const u_char *)ext + item_len;
trunc:
    ND_PRINT((ndo," [|%s]", NPSTR(ISAKMP_NPTYPE_N)));
    return NULL;
}

void
icmp_print(netdissect_options *ndo, const u_char *bp, u_int plen, const u_char *bp2,
           int fragmented)
{
    char *cp;
    const struct icmp *dp;
    const struct icmp_ext_t *ext_dp;
    const struct ip *ip;
    const char *str, *fmt;
    const struct ip *oip;
    const struct udphdr *ouh;
    const uint8_t *obj_tptr;
    uint32_t raw_label;
    const u_char *snapend_save;
    const struct icmp_mpls_ext_object_header_t *icmp_mpls_ext_object_header;
    u_int hlen, dport, mtu, obj_tlen, obj_class_num, obj_ctype;
    char buf[MAXHOSTNAMELEN + 100];
    struct cksum_vec vec[1];

    dp = (const struct icmp *)bp;
    ext_dp = (const struct icmp_ext_t *)bp;
    ip = (const struct ip *)bp2;
    str = buf;

    ND_TCHECK(dp->icmp_code);
    switch (dp->icmp_type) {

    case ICMP_ECHO:
    case ICMP_ECHOREPLY:
        ND_TCHECK(dp->icmp_seq);
        (void)snprintf(buf, sizeof(buf), "echo %s, id %u, seq %u",
                               dp->icmp_type == ICMP_ECHO ? "request" : "reply",
                               EXTRACT_16BITS(&dp->icmp_id),
                               EXTRACT_16BITS(&dp->icmp_seq));
        break;

    case ICMP_UNREACH:
        ND_TCHECK(dp->icmp_ip.ip_dst);
        switch (dp->icmp_code) {

        case ICMP_UNREACH_PROTOCOL:
            ND_TCHECK(dp->icmp_ip.ip_p);
            (void)snprintf(buf, sizeof(buf),
                "%s protocol %d unreachable",
                ipaddr_string(ndo, &dp->icmp_ip.ip_dst),
                dp->icmp_ip.ip_p);
            break;

        case ICMP_UNREACH_PORT:
            ND_TCHECK(dp->icmp_ip.ip_p);
            oip = &dp->icmp_ip;
            hlen = IP_HL(oip) * 4;
            ouh = (const struct udphdr *)(((const u_char *)oip) + hlen);
            ND_TCHECK(ouh->uh_dport);
            dport = EXTRACT_16BITS(&ouh->uh_dport);
            switch (oip->ip_p) {

            case IPPROTO_TCP:
                (void)snprintf(buf, sizeof(buf),
                    "%s tcp port %s unreachable",
                    ipaddr_string(ndo, &oip->ip_dst),
                    tcpport_string(ndo, dport));
                break;

            case IPPROTO_UDP:
                (void)snprintf(buf, sizeof(buf),
                    "%s udp port %s unreachable",
                    ipaddr_string(ndo, &oip->ip_dst),
                    udpport_string(ndo, dport));
                break;

            default:
                (void)snprintf(buf, sizeof(buf),
                    "%s protocol %d port %d unreachable",
                    ipaddr_string(ndo, &oip->ip_dst),
                    oip->ip_p, dport);
                break;
            }
            break;

        case ICMP_UNREACH_NEEDFRAG:
            {
                register const struct mtu_discovery *mp;
                mp = (const struct mtu_discovery *)(const u_char *)&dp->icmp_void;
                mtu = EXTRACT_16BITS(&mp->nexthopmtu);
                if (mtu) {
                    (void)snprintf(buf, sizeof(buf),
                        "%s unreachable - need to frag (mtu %d)",
                        ipaddr_string(ndo, &dp->icmp_ip.ip_dst), mtu);
                } else {
                    (void)snprintf(buf, sizeof(buf),
                        "%s unreachable - need to frag",
                        ipaddr_string(ndo, &dp->icmp_ip.ip_dst));
                }
            }
            break;

        default:
            fmt = tok2str(unreach2str, "#%d %%s unreachable", dp->icmp_code);
            (void)snprintf(buf, sizeof(buf), fmt, ipaddr_string(ndo, &dp->icmp_ip.ip_dst));
            break;
        }
        break;

    default:
        str = tok2str(icmp2str, "type-#%d", dp->icmp_type);
        break;
    }
    ND_PRINT((ndo, "ICMP %s, length %u", str, plen));
}

static void
bgp_capabilities_print(netdissect_options *ndo,
                       const u_char *opt, int caps_len)
{
	int cap_type, cap_len, tcap_len, cap_offset;
        int i = 0;

        while (i < caps_len) {
                ND_TCHECK2(opt[i], BGP_CAP_HEADER_SIZE);
                cap_type=opt[i];
                cap_len=opt[i+1];
                tcap_len=cap_len;
                ND_PRINT((ndo, "\n\t      %s (%u), length: %u",
                       tok2str(bgp_capcode_values, "Unknown",
                                  cap_type),
                       cap_type,
                       cap_len));
                ND_TCHECK2(opt[i+2], cap_len);
                switch (cap_type) {
                case BGP_CAPCODE_MP:
                    ND_PRINT((ndo, "\n\t\tAFI %s (%u), SAFI %s (%u)",
                           tok2str(af_values, "Unknown",
                                      EXTRACT_16BITS(opt+i+2)),
                           EXTRACT_16BITS(opt+i+2),
                           tok2str(bgp_safi_values, "Unknown",
                                      opt[i+5]),
                           opt[i+5]));
                    break;
                case BGP_CAPCODE_RESTART:
                    ND_PRINT((ndo, "\n\t\tRestart Flags: [%s], Restart Time %us",
                           ((opt[i+2])&0x80) ? "R" : "none",
                           EXTRACT_16BITS(opt+i+2)&0xfff));
                    tcap_len-=2;
                    cap_offset=4;
                    while(tcap_len>=4) {
                        ND_PRINT((ndo, "\n\t\t  AFI %s (%u), SAFI %s (%u), Forwarding state preserved: %s",
                               tok2str(af_values,"Unknown",
                                          EXTRACT_16BITS(opt+i+cap_offset)),
                               EXTRACT_16BITS(opt+i+cap_offset),
                               tok2str(bgp_safi_values,"Unknown",
                                          opt[i+cap_offset+2]),
                               opt[i+cap_offset+2],
                               ((opt[i+cap_offset+3])&0x80) ? "yes" : "no" ));
                        tcap_len-=4;
                        cap_offset+=4;
                    }
                    break;
                case BGP_CAPCODE_RR:
                case BGP_CAPCODE_RR_CISCO:
                    break;
                case BGP_CAPCODE_AS_NEW:

                    /*
                     * Extract the 4 byte AS number encoded.
                     */
                    if (cap_len == 4) {
                        ND_PRINT((ndo, "\n\t\t 4 Byte AS %s",
                            as_printf(ndo, astostr, sizeof(astostr),
                            EXTRACT_32BITS(opt + i + 2))));
                    }
                    break;
                case BGP_CAPCODE_ADD_PATH:
                    cap_offset=2;
                    if (tcap_len == 0) {
                        ND_PRINT((ndo, " (bogus)")); /* length */
                        break;
                    }
                    while (tcap_len > 0) {
                        if (tcap_len < 4) {
                            ND_PRINT((ndo, "\n\t\t(invalid)"));
                            break;
                        }
                        ND_PRINT((ndo, "\n\t\tAFI %s (%u), SAFI %s (%u), Send/Receive: %s",
                                  tok2str(af_values,"Unknown",EXTRACT_16BITS(opt+i+cap_offset)),
                                  EXTRACT_16BITS(opt+i+cap_offset),
                                  tok2str(bgp_safi_values,"Unknown",opt[i+cap_offset+2]),
                                  opt[i+cap_offset+2],
                                  tok2str(bgp_add_path_recvsend,"Bogus (0x%02x)",opt[i+cap_offset+3])
                        ));
                        tcap_len-=4;
                        cap_offset+=4;
                    }
                    break;
                default:
                    ND_PRINT((ndo, "\n\t\tno decoder for Capability %u",
                           cap_type));
                    if (ndo->ndo_vflag <= 1)
                        print_unknown_data(ndo, &opt[i+2], "\n\t\t", cap_len);
                    break;
                }
                if (ndo->ndo_vflag > 1 && cap_len > 0) {
                    print_unknown_data(ndo, &opt[i+2], "\n\t\t", cap_len);
                }
                i += BGP_CAP_HEADER_SIZE + cap_len;
        }
        return;

trunc:
	ND_PRINT((ndo, "[|BGP]"));
}

static int
ospf6_print_lshdr(netdissect_options *ndo,
                  register const struct lsa6_hdr *lshp, const u_char *dataend)
{
